45: // ConfigFor returns a copy of the provided config with the
46: // appropriate dynamic client defaults set.
47: func ConfigFor(inConfig *rest.Config) *rest.Config {
48: 	config := rest.CopyConfig(inConfig)
49: 
50: 	config.ContentType = "application/json"
51: 	config.AcceptContentTypes = "application/json"
52: 	if features.FeatureGates().Enabled(features.ClientsAllowCBOR) {
53: 		config.AcceptContentTypes = "application/json;q=0.9,application/cbor;q=1"
54: 		if features.FeatureGates().Enabled(features.ClientsPreferCBOR) {
55: 			config.ContentType = "application/cbor"
56: 		}
57: 	}
58: 
59: 	config.NegotiatedSerializer = newBasicNegotiatedSerializer()
60: 	if config.UserAgent == "" {
61: 		config.UserAgent = rest.DefaultKubernetesUserAgent()
62: 	}
63: 	return config
64: }
